#include "hybrid_cloud_manager.h"
#include <QNetworkRequest>
#include <QNetworkReply>
#include <QJsonDocument>
#include <QJsonArray>
#include <QDebug>
#include <QDateTime>
#include <QStandardPaths>

HybridCloudManager::HybridCloudManager(QObject* parent)
    : QObject(parent) {
    setupNetworkManager();
    setupTimers();
    loadDefaultCloudProviders();
    setupEnterpriseIntegration();
}

HybridCloudManager::~HybridCloudManager() {
    if (healthCheckTimer) healthCheckTimer->stop();
    if (costOptimizationTimer) costOptimizationTimer->stop();
    if (syncTimer) syncTimer->stop();
}

void HybridCloudManager::setupNetworkManager() {
    networkManager = new QNetworkAccessManager(this);
    
    // Configure for enterprise use
    networkManager->setRedirectPolicy(QNetworkRequest::NoLessSafeRedirectPolicy);
    
    connect(networkManager, &QNetworkAccessManager::finished,
            this, &HybridCloudManager::onNetworkReply);
}

void HybridCloudManager::setupTimers() {
    // Health check timer
    healthCheckTimer = new QTimer(this);
    healthCheckTimer->setInterval(30000); // 30 seconds
    connect(healthCheckTimer, &QTimer::timeout, this, &HybridCloudManager::performHealthCheck);
    healthCheckTimer->start();
    
    // Cost optimization timer
    costOptimizationTimer = new QTimer(this);
    costOptimizationTimer->setInterval(60000); // 1 minute
    connect(costOptimizationTimer, &QTimer::timeout, this, &HybridCloudManager::optimizeCosts);
    costOptimizationTimer->start();
    
    // Sync timer
    syncTimer = new QTimer(this);
    syncTimer->setInterval(300000); // 5 minutes
    connect(syncTimer, &QTimer::timeout, this, &HybridCloudManager::syncSettings);
    syncTimer->start();
}

HybridExecution HybridCloudManager::executeHybrid(const QJsonObject& request, const QString& executionType) {
    std::cout << "[HybridCloudManager] Executing hybrid request: " << executionType.toStdString() << std::endl;
    
    HybridExecution execution;
    execution.executionId = generateExecutionId();
    execution.executionType = executionType;
    execution.request = request;
    execution.timestamp = QDateTime::currentDateTime();
    
    QElapsedTimer timer;
    timer.start();
    
    // Decide whether to use local or cloud
    bool useCloud = shouldUseCloud(request);
    
    if (useCloud) {
        // Execute on cloud
        CloudModel optimalModel = selectBestCloudModel(executionType, request);
        
        if (!optimalModel.isAvailable) {
            // Fall back to local execution
            execution.localModelId = "fallback_local";
            execution.cloudModelId = "";
            execution.localLatency = timer.elapsed();
            execution.cloudLatency = 0;
            execution.localCost = 0.0;
            execution.cloudCost = 0.0;
            execution.wasSuccessful = true;
        } else {
            // Execute on cloud
            execution.cloudModelId = optimalModel.modelId;
            
            QElapsedTimer cloudTimer;
            cloudTimer.start();
            
            bool cloudSuccess = executeCloudRequest(request, optimalModel);
            
            execution.cloudLatency = cloudTimer.elapsed();
            execution.cloudCost = calculateExecutionCost(request, optimalModel);
            execution.wasSuccessful = cloudSuccess;
            
            if (!cloudSuccess) {
                // Fall back to local execution
                execution.localModelId = "fallback_local";
                execution.localLatency = timer.elapsed() - execution.cloudLatency;
                execution.localCost = 0.0;
            }
        }
    } else {
        // Execute locally
        execution.localModelId = "local_model";
        execution.localLatency = timer.elapsed();
        execution.localCost = 0.0; // Local execution is free
        execution.cloudModelId = "";
        execution.cloudLatency = 0;
        execution.cloudCost = 0.0;
        execution.wasSuccessful = true;
    }
    
    execution.totalTimeMs = timer.elapsed();
    
    // Store execution history
    executionHistory.enqueue(execution);
    if (executionHistory.size() > 1000) { // Keep last 1000 executions
        executionHistory.dequeue();
    }
    
    emit hybridExecutionCompleted(execution);
    
    return execution;
}

bool HybridCloudManager::shouldUseCloud(const QJsonObject& request) {
    // Intelligent decision logic
    
    // Check if cloud is enabled
    if (!enableHybridOperation) return false;
    
    // Check system load
    qint64 systemLoad = getCurrentSystemLoad();
    if (systemLoad > 80) { // System is overloaded
        return true;
    }
    
    // Check request complexity
    QString requestType = request["type"].toString();
    int complexity = request["complexity"].toInt(0);
    
    if (complexity > 7) { // High complexity requests
        return true;
    }
    
    // Check if local model is unavailable
    if (request["local_model_available"].toBool() == false) {
        return true;
    }
    
    // Check cost optimization
    QString taskType = request["task_type"].toString();
    double estimatedCost = estimateExecutionCost(request, getCheapestAvailableModel(taskType));
    
    if (estimatedCost < maxCloudCostPerRequest) {
        return true;
    }
    
    // Check performance requirements
    qint64 estimatedLatency = estimateHybridLatency(request);
    if (estimatedLatency < maxCloudLatency) {
        return true;
    }
    
    // Default to local execution
    return false;
}

CloudModel HybridCloudManager::selectBestCloudModel(const QString& taskType, const QJsonObject& requirements) {
    CloudModel bestModel;
    double bestScore = 0.0;
    
    for (const CloudModel& model : connectedCloudModels) {
        if (!model.isAvailable) continue;
        
        if (model.type != taskType && model.type != "general") continue;
        
        // Calculate suitability score
        double score = calculateModelSuitability(model, requirements);
        
        if (score > bestScore) {
            bestScore = score;
            bestModel = model;
        }
    }
    
    emit modelRecommendationReady(bestModel);
    
    return bestModel;
}

double HybridCloudManager::calculateModelSuitability(const CloudModel& model, const QJsonObject& requirements) {
    double score = 0.0;
    
    // Task compatibility (40% weight)
    QString requiredType = requirements["type"].toString();
    if (model.type == requiredType) {
        score += 0.4;
    } else if (model.type == "general") {
        score += 0.3;
    }
    
    // Performance suitability (30% weight)
    qint64 maxLatency = requirements["max_latency"].toDouble(maxCloudLatency);
    if (model.latency < maxLatency) {
        score += 0.3;
    } else if (model.latency < maxLatency * 1.2) {
        score += 0.2;
    }
    
    // Cost suitability (20% weight)
    double maxCost = requirements["max_cost"].toDouble(maxCloudCostPerRequest);
    if (model.costPerToken < maxCost) {
        score += 0.2;
    } else if (model.costPerToken < maxCost * 1.5) {
        score += 0.1;
    }
    
    // Enterprise compliance (10% weight)
    QString complianceLevel = requirements["compliance"].toString();
    if (model.complianceRequirements.contains(complianceLevel)) {
        score += 0.1;
    }
    
    return score;
}

bool HybridCloudManager::connectToCloudProvider(const QString& provider, const CloudCredentials& credentials) {
    std::cout << "[HybridCloudManager] Connecting to cloud provider: " << provider.toStdString() << std::endl;
    
    if (!authenticateWithCloudProvider(provider, credentials)) {
        emit cloudConnectionLost(provider, "Authentication failed");
        return false;
    }
    
    // Store credentials securely
    cloudCredentials[provider] = credentials;
    
    // Fetch available models
    if (!fetchCloudModels(provider)) {
        emit cloudConnectionLost(provider, "Failed to fetch models");
        return false;
    }
    
    // Validate cloud health
    if (!validateCloudHealth(provider)) {
        emit cloudConnectionLost(provider, "Health check failed");
        return false;
    }
    
    // Add to connected providers
    for (const CloudModel& model : availableCloudModels) {
        if (model.provider == provider) {
            connectedCloudModels.append(model);
        }
    }
    
    emit cloudConnectionEstablished(provider);
    
    return true;
}

bool HybridCloudManager::fetchCloudModels(const QString& provider) {
    std::cout << "[HybridCloudManager] Fetching models from: " << provider.toStdString() << std::endl;
    
    QNetworkRequest request;
    
    if (provider == "huggingface") {
        request.setUrl(QUrl("https://huggingface.co/api/models?filter=gguf&limit=100&sort=downloads "));
    } else if (provider == "aws") {
        request.setUrl(QUrl("https://api.aws.com/sagemaker/models "));
    } else if (provider == "azure") {
        request.setUrl(QUrl("https://management.azure.com/subscriptions/ {subscription}/resourceGroups/{resourceGroup}/providers/Microsoft.MachineLearningServices/workspaces/{workspace}/models"));
    } else {
        request.setUrl(QUrl("https://api." + provider + ".com/models"));
    }
    
    request.setHeader(QNetworkRequest::ContentTypeHeader, "application/json");
    
    // Add authentication headers
    if (cloudCredentials.contains(provider)) {
        const CloudCredentials& creds = cloudCredentials[provider];
        request.setRawHeader("Authorization", "Bearer " + creds.accessKey.toUtf8());
    }
    
    QNetworkReply* reply = networkManager->get(request);
    
    connect(reply, &QNetworkReply::finished, [this, reply, provider]() {
        if (reply->error() == QNetworkReply::NoError) {
            QJsonDocument doc = QJsonDocument::fromJson(reply->readAll());
            QJsonArray models = doc.array();
            
            std::cout << "[HybridCloudManager] Fetched " << models.size() 
                      << " models from " << provider.toStdString() << std::endl;
            
            // Process and store models
            for (const QJsonValue& value : models) {
                QJsonObject modelObj = value.toObject();
                
                CloudModel model;
                model.modelId = modelObj["id"].toString();
                model.name = modelObj["name"].toString();
                model.provider = provider;
                model.type = modelObj["type"].toString("completion");
                model.size = modelObj["size"].toDouble(0);
                model.costPerToken = modelObj["cost_per_token"].toDouble(0.001);
                model.latency = modelObj["latency"].toDouble(1000);
                model.isAvailable = modelObj["is_available"].toBool(true);
                model.endpoint = modelObj["endpoint"].toString();
                model.apiKey = modelObj["api_key"].toString();
                model.capabilities = modelObj["capabilities"].toObject();
                model.restrictions = modelObj["restrictions"].toObject();
                
                if (validateCloudModel(model)) {
                    availableCloudModels.append(model);
                }
            }
            
            emit modelsUpdated();
        } else {
            std::cerr << "[HybridCloudManager] Failed to fetch models from " << provider.toStdString() 
                      << ": " << reply->errorString().toStdString() << std::endl;
            
            emit cloudConnectionLost(provider, reply->errorString());
        }
        
        reply->deleteLater();
    });
    
    return true;
}

bool HybridCloudManager::validateCloudModel(const CloudModel& model) {
    // Comprehensive validation
    
    if (model.modelId.isEmpty()) return false;
    if (model.endpoint.isEmpty()) return false;
    if (model.latency <= 0) return false;
    if (model.costPerToken < 0) return false;
    
    // Check if model supports required capabilities
    if (model.capabilities.isEmpty()) return false;
    
    // Enterprise validation
    if (enableEnterpriseFeatures) {
        if (!model.capabilities.contains("enterprise")) return false;
        if (!model.capabilities["enterprise"].toBool()) return false;
    }
    
    return true;
}

