QJsonObject HybridCloudManager::buildCloudRequest(const QJsonObject& request, const CloudModel& model) {
    QJsonObject cloudRequest;
    
    // Build provider-specific request format
    if (model.provider == "huggingface") {
        cloudRequest["inputs"] = request["prompt"].toString();
        cloudRequest["parameters"] = QJsonObject{
            {"temperature", request["temperature"].toDouble(0.7)},
            {"max_new_tokens", request["max_tokens"].toInt(150)},
            {"top_p", request["top_p"].toDouble(0.9)},
            {"do_sample", true}
        };
    } else if (model.provider == "aws") {
        cloudRequest["body"] = QJsonObject{
            {"inputText", request["prompt"].toString()},
            {"textGenerationConfig", QJsonObject{
                {"temperature", request["temperature"].toDouble(0.7)},
                {"topP", request["top_p"].toDouble(0.9)},
                {"maxTokenCount", request["max_tokens"].toInt(150)}
            }}
        };
    } else if (model.provider == "azure") {
        cloudRequest["messages"] = QJsonArray{
            QJsonObject{{"role", "user"}, {"content", request["prompt"].toString()}}
        };
        cloudRequest["temperature"] = request["temperature"].toDouble(0.7);
        cloudRequest["max_tokens"] = request["max_tokens"].toInt(150);
        cloudRequest["top_p"] = request["top_p"].toDouble(0.9);
    } else {
        // Generic format
        cloudRequest["prompt"] = request["prompt"].toString();
        cloudRequest["temperature"] = request["temperature"].toDouble(0.7);
        cloudRequest["max_tokens"] = request["max_tokens"].toInt(150);
    }
    
    // Add enterprise headers if enabled
    if (enableEnterpriseFeatures) {
        cloudRequest["enterprise_context"] = QJsonObject{
            {"account_id", enterpriseAccountId},
            {"team_id", teamId},
            {"department", department},
            {"compliance_level", complianceLevel}
        };
    }
    
    return cloudRequest;
}

void HybridCloudManager::performHealthCheck() {
    std::cout << "[HybridCloudManager] Performing health check..." << std::endl;
    
    for (const QString& provider : cloudCredentials.keys()) {
        bool isHealthy = validateCloudHealth(provider);
        
        if (!isHealthy) {
            std::cerr << "[HybridCloudManager] Health check failed for: " 
                      << provider.toStdString() << std::endl;
            emit cloudConnectionLost(provider, "Health check failed");
            
            if (enableCloudFailover) {
                handleCloudFailure(provider, "Health check failure");
            }
        }
    }
    
    emit cloudHealthStatusChanged(true);
}

bool HybridCloudManager::validateCloudHealth(const QString& provider) {
    if (!cloudCredentials.contains(provider)) return false;
    
    // Simple health check - ping the provider's status endpoint
    QNetworkRequest request;
    
    if (provider == "huggingface") {
        request.setUrl(QUrl("https://huggingface.co/api/status"));
    } else if (provider == "aws") {
        request.setUrl(QUrl("https://status.aws.amazon.com/data.json"));
    } else if (provider == "azure") {
        request.setUrl(QUrl("https://status.azure.com/en-us/status"));
    } else {
        return true; // Assume healthy for unknown providers
    }
    
    QNetworkReply* reply = networkManager->get(request);
    
    // Wait for response with timeout
    QEventLoop loop;
    QTimer timeoutTimer;
    timeoutTimer.setSingleShot(true);
    timeoutTimer.setInterval(5000); // 5 second timeout
    
    connect(reply, &QNetworkReply::finished, &loop, &QEventLoop::quit);
    connect(&timeoutTimer, &QTimer::timeout, &loop, &QEventLoop::quit);
    
    timeoutTimer.start();
    loop.exec();
    
    bool isHealthy = (reply->error() == QNetworkReply::NoError);
    reply->deleteLater();
    
    return isHealthy && !timeoutTimer.isActive();
}

void HybridCloudManager::optimizeCosts() {
    if (!enableCostOptimization) return;
    
    std::cout << "[HybridCloudManager] Running cost optimization..." << std::endl;
    
    double totalCost = 0.0;
    qint64 totalLatency = 0;
    int successfulExecutions = 0;
    
    // Analyze recent execution history
    for (const HybridExecution& execution : executionHistory) {
        if (execution.wasSuccessful) {
            totalCost += execution.cloudCost;
            totalLatency += execution.cloudLatency;
            successfulExecutions++;
        }
    }
    
    if (successfulExecutions > 0) {
        double avgCost = totalCost / successfulExecutions;
        qint64 avgLatency = totalLatency / successfulExecutions;
        
        std::cout << "[HybridCloudManager] Cost analytics - Avg cost: $" 
                  << avgCost << ", Avg latency: " << avgLatency << "ms" << std::endl;
        
        // Update cost thresholds based on analytics
        if (avgCost > maxCloudCostPerRequest * 1.5) {
            maxCloudCostPerRequest *= 0.9; // Reduce threshold by 10%
            std::cout << "[HybridCloudManager] Reduced cost threshold to: $" 
                      << maxCloudCostPerRequest << std::endl;
        }
        
        emit cloudCostUpdated(totalCost);
    }
    
    emit hybridMetricsUpdated(getHybridMetrics());
}

QJsonObject HybridCloudManager::getHybridMetrics() const {
    QJsonObject metrics;
    
    metrics["total_executions"] = executionHistory.size();
    metrics["successful_executions"] = 0;
    metrics["failed_executions"] = 0;
    metrics["total_cloud_cost"] = 0.0;
    metrics["avg_cloud_latency"] = 0;
    metrics["hybrid_enabled"] = enableHybridOperation;
    metrics["cloud_providers_connected"] = connectedCloudModels.size();
    metrics["available_cloud_models"] = availableCloudModels.size();
    
    int successfulCount = 0;
    qint64 totalLatency = 0;
    double totalCost = 0.0;
    
    for (const HybridExecution& execution : executionHistory) {
        if (execution.wasSuccessful) {
            metrics["successful_executions"] = metrics["successful_executions"].toInt() + 1;
            totalLatency += execution.cloudLatency;
            totalCost += execution.cloudCost;
            successfulCount++;
        } else {
            metrics["failed_executions"] = metrics["failed_executions"].toInt() + 1;
        }
    }
    
    if (successfulCount > 0) {
        metrics["avg_cloud_latency"] = totalLatency / successfulCount;
        metrics["total_cloud_cost"] = totalCost;
        metrics["avg_cloud_cost"] = totalCost / successfulCount;
    }
    
    return metrics;
}

