    QJsonObject documentation;
    documentation["type"] = "function_doc";
    documentation["function_name"] = functionName;
    documentation["template"] = QString("/**\n * %1 - [DESCRIPTION]\n * @param {[TYPE]} [PARAM] - [DESCRIPTION]\n * @returns {[TYPE]} [DESCRIPTION]\n * @example\n * [EXAMPLE_USAGE]\n */")
        .arg(functionName);
    documentation["parameters"] = QJsonArray::fromStringList(extractParameters(code));
    
    suggestion.implementation = documentation;
