}

double AutonomousFeatureEngine::calculateSuggestionConfidence(const AutonomousSuggestion& suggestion) const {
    double confidence = 0.5; // Base confidence
    
    // Type-specific confidence adjustments
    if (suggestion.type == "security") {
        confidence += 0.3; // High confidence for security
    } else if (suggestion.type == "test") {
        confidence += 0.2; // Good confidence for tests
    } else if (suggestion.type == "optimization") {
        confidence += 0.1; // Moderate confidence for optimizations
    } else if (suggestion.type == "documentation") {
        confidence += 0.15; // Good confidence for docs
    }
    
    // Adjust based on user profile
    if (userProfile.codingStyle == "enterprise") {
        confidence += 0.1;
    } else if (userProfile.codingStyle == "minimal") {
        confidence -= 0.1;
    }
    
    // Ensure confidence is between 0 and 1
    return std::min(1.0, std::max(0.0, confidence));
}

QString AutonomousFeatureEngine::extractFunctionName(const QString& functionCode) const {
    QRegularExpression funcRegex(R"((?:function\s+)?(\w+)\s*\([^)]*\)\s*\{)");
    QRegularExpressionMatch match = funcRegex.match(functionCode);
    
    if (match.hasMatch()) {
        return match.captured(1);
    }
    
    return "unknown_function";
}

QVector<QString> AutonomousFeatureEngine::extractParameters(const QString& functionCode) const {
    QVector<QString> parameters;
    
    QRegularExpression paramRegex(R"(\(([^)]*)\))");
    QRegularExpressionMatch match = paramRegex.match(functionCode);
    
    if (match.hasMatch()) {
        QString paramList = match.captured(1);
        QStringList paramNames = paramList.split(',', Qt::SkipEmptyParts);
        
        for (const QString& param : paramNames) {
            parameters.append(param.trimmed());
        }
    }
    
    return parameters;
}

QVector<QString> AutonomousFeatureEngine::detectPerformanceIssues(const QString& code) const {
    QVector<QString> issues;
    
    // Simple performance anti-patterns
    if (code.contains("for") && code.contains("strlen")) {
        issues.append("strlen in loop condition - O(n) per iteration");
    }
    
    if (code.contains("new ") && code.contains("delete")) {
        issues.append("Manual memory management - consider smart pointers");
    }
    
    if (code.contains("vector") && code.contains("push_back") && code.contains("reserve")) {
        issues.append("Missing reserve() call before multiple push_back operations");
    }
    
    return issues;
}

QVector<QString> AutonomousFeatureEngine::detectCommonVulnerabilities(const QString& code) const {
    QVector<QString> vulnerabilities;
    
    // SQL Injection patterns
    if (code.contains("SELECT") && code.contains("+") && code.contains("request")) {
        vulnerabilities.append("Potential SQL injection - unsanitized user input concatenation");
    }
    
    // Buffer overflow patterns
    if (code.contains("strcpy") || code.contains("strcat")) {
        vulnerabilities.append("Unsafe string operations - potential buffer overflow");
    }
    
    // Command injection
    if (code.contains("system(") && code.contains("user")) {
        vulnerabilities.append("Potential command injection - unsanitized system calls");
    }
    
    return vulnerabilities;
}

QJsonObject AutonomousFeatureEngine::parseCodeAST(const QString& code, const QString& language) const {
    QJsonObject ast;
    
    // Simplified AST parsing - in real implementation would use proper parser
    if (language == "cpp" || language == "c") {
        // Count functions
        QRegularExpression funcRegex(R"(\w+\s+\w+\s*\([^)]*\)\s*\{)");
        int functionCount = 0;
        QRegularExpressionMatchIterator i = funcRegex.globalMatch(code);
        while (i.hasNext()) {
            i.next();
            functionCount++;
        }
        ast["function_count"] = functionCount;
        
        // Count classes
        QRegularExpression classRegex(R"(class\s+\w+)");
        int classCount = 0;
        QRegularExpressionMatchIterator j = classRegex.globalMatch(code);
        while (j.hasNext()) {
            j.next();
            classCount++;
        }
        ast["class_count"] = classCount;
    }
    
    ast["line_count"] = code.count('\n') + 1;
    ast["complexity"] = code.contains("if") ? "moderate" : "simple";
    
    return ast;
}

QString AutonomousFeatureEngine::detectLanguage(const QString& filePath) const {
    if (filePath.endsWith(".cpp") || filePath.endsWith(".cc") || filePath.endsWith(".h")) {
        return "cpp";
    } else if (filePath.endsWith(".py")) {
        return "python";
    } else if (filePath.endsWith(".js") || filePath.endsWith(".ts")) {
        return "javascript";
    } else if (filePath.endsWith(".java")) {
        return "java";
    } else if (filePath.endsWith(".cs")) {
        return "csharp";
    }
    
    return "unknown";
}

