QJsonObject AutonomousFeatureEngine::extractFunctionSignatures(const QString& code) const {
    QJsonObject signatures;
    
    QRegularExpression funcRegex(R"((\w+)\s*\(([^)]*)\)\s*\{)");
    QRegularExpressionMatchIterator i = funcRegex.globalMatch(code);
    
    while (i.hasNext()) {
        QRegularExpressionMatch match = i.next();
        QString funcName = match.captured(1);
        QString params = match.captured(2);
        
        QJsonObject sig;
        sig["parameters"] = QJsonArray::fromStringList(params.split(',', Qt::SkipEmptyParts));
        sig["return_type"] = "auto"; // Simplified
        
        signatures[funcName] = sig;
    }
    
