bool DeploymentManager::performFullInstallation() {
    std::cout << "[DeploymentManager] Starting full installation..." << std::endl;
    
    emit installationStarted();
    isInstalling = true;
    installationErrors.clear();
    installationWarnings.clear();
    installLog.clear();
    
    double progress = 0.0;
    const double progressStep = 100.0 / (components.size() + 5); // +5 for system checks
    
    // Step 1: System requirements check
    emit installationProgress(progress, "Checking system requirements...");
    if (!checkSystemRequirements()) {
        logError("System requirements check failed");
        emit installationError("System requirements not met");
        emit installationCompleted(false);
        return false;
    }
    progress += progressStep;
    
    // Step 2: Create directory structure
    emit installationProgress(progress, "Creating directory structure...");
    if (!createDirectoryStructure()) {
        logError("Failed to create directory structure");
        emit installationError("Directory creation failed");
        emit installationCompleted(false);
        return false;
    }
    progress += progressStep;
    
    // Step 3: Install components
    for (const DeploymentComponent& component : components) {
        if (!component.isEnabled) continue;
        
        emit installationProgress(progress, QString("Installing %1...").arg(component.name));
        
        if (!installComponent(component)) {
            if (component.isCritical) {
                logError(QString("Critical component %1 installation failed").arg(component.name));
                emit installationError(QString("Installation of critical component %1 failed").arg(component.name));
                emit installationCompleted(false);
                return false;
            } else {
                logWarning(QString("Optional component %1 installation failed").arg(component.name));
                emit installationWarning(QString("Optional component %1 installation failed").arg(component.name));
            }
        }
        
        progress += progressStep;
    }
    
    // Step 4: Configure installation
    emit installationProgress(progress, "Configuring installation...");
    QJsonObject defaultConfig = generateDefaultConfiguration();
    if (!applyConfiguration(defaultConfig)) {
        logWarning("Configuration application failed");
        emit installationWarning("Configuration application failed");
    }
    progress += progressStep;
    
    // Step 5: IDE integration
    emit installationProgress(progress, "Integrating with IDE...");
    if (!integrateWithIDE()) {
        logWarning("IDE integration failed");
        emit installationWarning("IDE integration failed");
    }
    progress += progressStep;
    
    // Step 6: Final validation
    emit installationProgress(95.0, "Validating installation...");
    if (!validateInstallation()) {
        logWarning("Installation validation failed");
        emit installationWarning("Installation validation failed");
