bool DeploymentManager::validateInstallation() {
    std::cout << "[DeploymentManager] Validating installation..." << std::endl;
    
    emit validationStarted();
    
    isValidating = true;
    bool allValid = true;
    double progress = 0.0;
    const double progressStep = 100.0 / components.size();
    
    // Validate each component
    for (const DeploymentComponent& component : components) {
        emit validationProgress(progress);
        
        if (component.isEnabled && component.status != "installed") {
            logError(QString("Component %1 is not installed").arg(component.name));
            allValid = false;
        }
        
        // Check component files exist
        QString componentPath = installBasePath + "/" + component.installPath;
        QDir componentDir(componentPath);
        
        if (!componentDir.exists()) {
            logError(QString("Component directory missing: %1").arg(componentPath));
            allValid = false;
        }
        
        progress += progressStep;
    }
    
    // Run installation tests
    if (allValid) {
        allValid = runInstallationTests();
    }
    
    isValidating = false;
    emit validationCompleted(allValid);
    
    std::cout << "[DeploymentManager] Installation validation " 
              << (allValid ? "passed" : "failed") << std::endl;
    
    return allValid;
}

