void AutonomousSuggestionWidget::addSuggestion(const AutonomousSuggestion& suggestion) {
    QWidget* suggestionWidget = createSuggestionWidget(suggestion);
    suggestionsLayout->insertWidget(suggestionsLayout->count() - 1, suggestionWidget);
    
    updateStats();
    
    // Auto-apply high-confidence security suggestions
    if (suggestion.type == "security" && suggestion.confidenceScore > 0.9 && suggestion.isAutoApplicable) {
        QTimer::singleShot(1000, [this, suggestion]() {
            emit suggestionAutoApplied(suggestion.suggestionId);
        });
    }
}

QWidget* AutonomousSuggestionWidget::createSuggestionWidget(const AutonomousSuggestion& suggestion) {
    QGroupBox* groupBox = new QGroupBox();
    groupBox->setStyleSheet("QGroupBox { border: 1px solid #ddd; border-radius: 5px; margin-top: 5px; }");
    
    QVBoxLayout* layout = new QVBoxLayout(groupBox);
    
    // Header with type and confidence
    QHBoxLayout* headerLayout = new QHBoxLayout();
    
    QString typeIcon = getIconForType(suggestion.type);
    QLabel* typeLabel = new QLabel(typeIcon);
    headerLayout->addWidget(typeLabel);
    
    QLabel* titleLabel = new QLabel(suggestion.suggestion);
    titleLabel->setStyleSheet("font-weight: bold;");
    headerLayout->addWidget(titleLabel);
    
    headerLayout->addStretch();
    
    // Confidence indicator
    QProgressBar* confidenceBar = new QProgressBar();
    confidenceBar->setRange(0, 100);
    confidenceBar->setValue(static_cast<int>(suggestion.confidenceScore * 100));
    confidenceBar->setTextVisible(true);
    confidenceBar->setFixedWidth(100);
    confidenceBar->setStyleSheet(getConfidenceStyle(suggestion.confidenceScore));
    headerLayout->addWidget(confidenceBar);
    
    layout->addLayout(headerLayout);
    
    // Reasoning
    if (!suggestion.reasoning.isEmpty()) {
        QLabel* reasoningLabel = new QLabel(suggestion.reasoning);
        reasoningLabel->setStyleSheet("color: #666; font-size: 12px;");
        reasoningLabel->setWordWrap(true);
        layout->addWidget(reasoningLabel);
    }
    
    // Action buttons
    QHBoxLayout* buttonLayout = new QHBoxLayout();
    
    QPushButton* applyButton = new QPushButton("Apply");
    applyButton->setEnabled(suggestion.isAutoApplicable);
    connect(applyButton, &QPushButton::clicked, [this, suggestion]() {
        emit suggestionAccepted(suggestion.suggestionId);
    });
    buttonLayout->addWidget(applyButton);
    
    QPushButton* previewButton = new QPushButton("Preview");
    connect(previewButton, &QPushButton::clicked, [this, suggestion]() {
        emit suggestionPreview(suggestion.suggestionId);
    });
    buttonLayout->addWidget(previewButton);
    
    QPushButton* dismissButton = new QPushButton("Dismiss");
    connect(dismissButton, &QPushButton::clicked, [this, suggestion]() {
        emit suggestionRejected(suggestion.suggestionId);
    });
    buttonLayout->addWidget(dismissButton);
    
    buttonLayout->addStretch();
    
    // Type-specific actions
    if (suggestion.type == "test") {
        QPushButton* generateTestsButton = new QPushButton("Generate Tests");
        connect(generateTestsButton, &QPushButton::clicked, [this, suggestion]() {
            emit generateTestsRequested(suggestion.targetFile);
        });
        buttonLayout->addWidget(generateTestsButton);
    } else if (suggestion.type == "documentation") {
        QPushButton* generateDocsButton = new QPushButton("Generate Docs");
        connect(generateDocsButton, &QPushButton::clicked, [this, suggestion]() {
            emit generateDocumentationRequested(suggestion.targetFile);
        });
        buttonLayout->addWidget(generateDocsButton);
    }
    
    layout->addLayout(buttonLayout);
    
    return groupBox;
}

QString AutonomousSuggestionWidget::getIconForType(const QString& type) const {
    if (type == "test") return "🧪";
    if (type == "security") return "🔒";
    if (type == "optimization") return "⚡";
    if (type == "documentation") return "📚";
    if (type == "refactoring") return "🔧";
    return "💡";
}

QString AutonomousSuggestionWidget::getConfidenceStyle(double confidence) const {
    QString color;
    if (confidence > 0.8) color = "#28a745"; // Green
    else if (confidence > 0.6) color = "#ffc107"; // Yellow
    else color = "#dc3545"; // Red
    
    return QString("QProgressBar::chunk { background-color: %1; }").arg(color);
}

void AutonomousSuggestionWidget::updateStats() {
    int totalSuggestions = suggestionsLayout->count() - 1; // Subtract the stretch
    int highConfidenceCount = 0;
    
    for (int i = 0; i < suggestionsLayout->count() - 1; ++i) {
        QWidget* widget = suggestionsLayout->itemAt(i)->widget();
        if (widget) {
            QProgressBar* confidenceBar = widget->findChild<QProgressBar*>();
            if (confidenceBar && confidenceBar->value() > 80) {
                highConfidenceCount++;
            }
        }
    }
    
    statsLabel->setText(QString("%1 suggestions (%2 high confidence)").arg(totalSuggestions).arg(highConfidenceCount));
}

