void SecurityAlertWidget::addSecurityAlert(const QString& file, int line, const QString& issue) {
    QWidget* alertWidget = createAlertWidget(file, line, issue);
    alertsLayout->insertWidget(alertsLayout->count() - 1, alertWidget);
    
    // Auto-apply critical security fixes
    if (issue.contains("SQL injection") || issue.contains("buffer overflow")) {
        QTimer::singleShot(2000, [this, file, line]() {
            emit autoFixRequested(file, line);
        });
    }
}

QWidget* SecurityAlertWidget::createAlertWidget(const QString& file, int line, const QString& issue) {
    QFrame* frame = new QFrame();
    frame->setFrameStyle(QFrame::Box);
    frame->setStyleSheet("QFrame { background-color: white; border: 1px solid #dc3545; border-radius: 3px; }");
    
    QVBoxLayout* layout = new QVBoxLayout(frame);
    
    // Issue description
    QLabel* issueLabel = new QLabel(issue);
    issueLabel->setStyleSheet("font-weight: bold; color: #dc3545;");
    issueLabel->setWordWrap(true);
    layout->addWidget(issueLabel);
    
    // Location
    QString location = QString("File: %1").arg(file);
    if (line > 0) {
        location += QString(" (Line: %1)").arg(line);
    }
    
    QLabel* locationLabel = new QLabel(location);
    locationLabel->setStyleSheet("color: #666; font-size: 12px;");
    layout->addWidget(locationLabel);
    
    // Actions
    QHBoxLayout* actionLayout = new QHBoxLayout();
    
    QPushButton* fixButton = new QPushButton("Auto Fix");
    fixButton->setStyleSheet("background-color: #28a745;");
    connect(fixButton, &QPushButton::clicked, [this, file, line]() {
        emit autoFixRequested(file, line);
    });
    actionLayout->addWidget(fixButton);
    
    QPushButton* ignoreButton = new QPushButton("Ignore");
    connect(ignoreButton, &QPushButton::clicked, [frame]() {
        frame->hide();
    });
    actionLayout->addWidget(ignoreButton);
    
    actionLayout->addStretch();
    
    layout->addLayout(actionLayout);
    
    return frame;
}

void SecurityAlertWidget::clearAllAlerts() {
    while (alertsLayout->count() > 1) { // Keep the stretch item
        QLayoutItem* item = alertsLayout->takeAt(0);
        if (item->widget()) {
            delete item->widget();
        }
        delete item;
    }
}

