void ErrorRecoverySystem::recordError(const QString& component, const QString& errorType, 
                                     const QString& message, const QJsonObject& context) {
    ErrorRecord error;
    error.errorId = generateErrorId();
    error.component = component;
    error.errorType = errorType;
    error.message = message;
    error.timestamp = QDateTime::currentDateTime();
    error.context = context;
    error.isRecovered = false;
    error.retryCount = 0;
    error.maxRetries = 3; // Default retry limit
    
    // Set max retries based on error type
    if (errorType == "critical") {
        error.maxRetries = 1;
    } else if (errorType == "warning") {
        error.maxRetries = 3;
    } else {
        error.maxRetries = 5;
    }
    
    errorHistory.append(error);
    totalErrors++;
    
    // Update statistics
    updateErrorStatistics(error);
    
    // Log error
    logError(error);
    
    // Attempt auto-recovery if enabled
    if (enableAutoRecovery && canAutoRecover(errorType)) {
        QTimer::singleShot(100, [this, error]() {
            attemptRecovery(error.errorId);
        });
    }
    
    emit errorRecorded(error);
    
    // Cleanup old errors if history is too large
    if (errorHistory.size() > maxErrorHistory) {
        cleanupOldErrors();
    }
    
    std::cout << "[ErrorRecovery] " << errorType.toStdString() << " error in " 
              << component.toStdString() << ": " << message.toStdString() << std::endl;
}

void ErrorRecoverySystem::recordCriticalFailure(const QString& component, const QString& message, 
                                               const QString& stackTrace) {
    recordError(component, "critical", message, QJsonObject{{"stack_trace", stackTrace}});
    criticalFailures++;
    
    emit criticalFailureDetected(component, message);
    
    std::cerr << "[CRITICAL FAILURE] " << component.toStdString() << ": " 
              << message.toStdString() << std::endl;
    if (!stackTrace.isEmpty()) {
        std::cerr << "Stack trace: " << stackTrace.toStdString() << std::endl;
    }
}

void ErrorRecoverySystem::recordWarning(const QString& component, const QString& message, 
                                       const QJsonObject& context) {
    recordError(component, "warning", message, context);
}

bool ErrorRecoverySystem::attemptRecovery(const QString& errorId) {
    auto it = std::find_if(errorHistory.begin(), errorHistory.end(),
                          [&errorId](const ErrorRecord& error) {
                              return error.errorId == errorId && !error.isRecovered;
                          });
    
    if (it == errorHistory.end()) {
        return false;
    }
    
    ErrorRecord& error = *it;
    
    if (error.retryCount >= error.maxRetries) {
        std::cout << "[Recovery] Max retries reached for error " << errorId.toStdString() << std::endl;
        return false;
    }
    
    error.retryCount++;
    
    // Find appropriate recovery strategy
    RecoveryStrategy strategy = findRecoveryStrategy(error);
    if (strategy.strategyId.isEmpty()) {
        std::cout << "[Recovery] No recovery strategy found for error type: " 
                  << error.errorType.toStdString() << std::endl;
        return false;
    }
    
    std::cout << "[Recovery] Attempting recovery for error " << errorId.toStdString() 
              << " using strategy " << strategy.strategyId.toStdString() << std::endl;
    
    // Execute recovery sequence
    executeRecoverySequence(strategy.strategyId, error);
    
    // Mark as recovered if successful
    error.isRecovered = true;
    error.recoveryAction = strategy.strategyId;
    recoveredErrors++;
    
    emit recoveryAttempted(errorId, true);
    
    return true;
}

void ErrorRecoverySystem::executeRecoverySequence(const QString& strategyId, const ErrorRecord& error) {
    auto strategyIt = recoveryStrategies.find(strategyId);
    if (strategyIt == recoveryStrategies.end()) {
        return;
    }
    
    const RecoveryStrategy& strategy = strategyIt.value();
    bool allStepsSuccessful = true;
    
    for (const QString& step : strategy.recoverySteps) {
        std::cout << "[Recovery] Executing step: " << step.toStdString() << std::endl;
        
        if (!executeRecoveryStep(step, error.context)) {
            std::cout << "[Recovery] Step failed: " << step.toStdString() << std::endl;
            allStepsSuccessful = false;
            break;
        }
        
        // Delay between steps if specified
        if (strategy.retryDelayMs > 0) {
            QThread::msleep(strategy.retryDelayMs);
        }
    }
    
    if (allStepsSuccessful) {
        std::cout << "[Recovery] Recovery sequence completed successfully" << std::endl;
    } else if (!strategy.fallbackAction.isEmpty()) {
        std::cout << "[Recovery] Executing fallback action: " << strategy.fallbackAction.toStdString() << std::endl;
        executeRecoveryStep(strategy.fallbackAction, error.context);
    }
    
    emit recoveryStrategyExecuted(strategyId, allStepsSuccessful);
}

bool ErrorRecoverySystem::executeRecoveryStep(const QString& step, const QJsonObject& context) {
    // Execute specific recovery actions based on step name
    if (step == "retry_model_load") {
        // In real implementation, would retry model loading
        return true;
    } else if (step == "fallback_to_local_model") {
        // Switch to local model
        return true;
    } else if (step == "switch_to_backup_provider") {
        // Switch to backup cloud provider
        return true;
    } else if (step == "enable_offline_mode") {
        // Enable offline operation
        return true;
    } else if (step == "reset_analysis_state") {
        // Reset autonomous analysis state
        return true;
    } else if (step == "clear_caches") {
        // Clear memory caches
        return true;
    } else if (step == "release_unused_resources") {
        // Release unused memory/resources
        return true;
    } else if (step == "notify_user_status") {
        // Notify user of status change
        return true;
    } else if (step == "log_analysis_failure") {
        // Log the analysis failure
        return true;
    }
    
    // Default: step not recognized
    return false;
}

RecoveryStrategy ErrorRecoverySystem::findRecoveryStrategy(const ErrorRecord& error) const {
    // Find matching recovery strategy based on error pattern and component
    for (const auto& [strategyId, strategy] : recoveryStrategies) {
        if (strategy.component == error.component) {
            // Simple pattern matching - in real implementation would be more sophisticated
            if (error.message.contains(strategy.errorPattern, Qt::CaseInsensitive)) {
                return strategy;
            }
        }
    }
    
    return RecoveryStrategy(); // Return empty strategy if no match found
}

void ErrorRecoverySystem::performHealthCheck() {
    std::cout << "[HealthCheck] Performing system health check..." << std::endl;
    
    bool systemHealthy = isSystemHealthy();
    
    // Check each component
    QJsonObject healthData = getSystemHealth();
    
    if (!systemHealthy) {
        QVector<QString> unhealthyComponents = getUnhealthyComponents();
        
        std::cerr << "[HealthCheck] Unhealthy components detected: ";
        for (const QString& component : unhealthyComponents) {
            std::cerr << component.toStdString() << " ";
        }
        std::cerr << std::endl;
        
        // Attempt recovery for unhealthy components
        for (const QString& component : unhealthyComponents) {
            recordWarning(component, "Component unhealthy during health check");
            
            if (enableAutoRecovery) {
                QTimer::singleShot(1000, [this, component]() {
                    resetComponent(component);
                });
            }
        }
    }
    
    emit systemHealthChanged(systemHealthy);
}

QJsonObject ErrorRecoverySystem::getSystemHealth() const {
    QJsonObject health;
    
    health["system_healthy"] = isSystemHealthy();
    health["total_errors"] = totalErrors;
    health["recovered_errors"] = recoveredErrors;
    health["critical_failures"] = criticalFailures;
    health["recovery_success_rate"] = getRecoverySuccessRate();
    
    QJsonObject componentHealth;
    for (auto it = errorCountsByComponent.begin(); it != errorCountsByComponent.end(); ++it) {
        QJsonObject compHealth;
        compHealth["error_count"] = it.value();
        compHealth["healthy"] = it.value() < 5; // Less than 5 errors is healthy
        componentHealth[it.key()] = compHealth;
    }
    health["components"] = componentHealth;
    
    return health;
}

bool ErrorRecoverySystem::isSystemHealthy() const {
    // System is healthy if:
    // 1. No recent critical failures
    // 2. Recovery success rate is acceptable (>70%)
    // 3. No component has excessive errors (>10)
    
    if (criticalFailures > 3) return false;
    if (getRecoverySuccessRate() < 0.7) return false;
    
    for (auto it = errorCountsByComponent.begin(); it != errorCountsByComponent.end(); ++it) {
        if (it.value() > 10) return false;
    }
    
    return true;
}

QVector<QString> ErrorRecoverySystem::getUnhealthyComponents() const {
    QVector<QString> unhealthy;
    
    for (auto it = errorCountsByComponent.begin(); it != errorCountsByComponent.end(); ++it) {
        if (it.value() > 5) { // More than 5 errors is unhealthy
            unhealthy.append(it.key());
        }
    }
    
    return unhealthy;
}

double ErrorRecoverySystem::getRecoverySuccessRate() const {
    if (totalErrors == 0) return 1.0;
    return static_cast<double>(recoveredErrors) / totalErrors;
}

QString ErrorRecoverySystem::generateErrorId() const {
    return QString("err_%1_%2")
        .arg(QDateTime::currentDateTime().toMSecsSinceEpoch())
        .arg(qrand() % 10000);
}

void ErrorRecoverySystem::updateErrorStatistics(const ErrorRecord& error) {
    errorCountsByComponent[error.component]++;
    errorCountsByType[error.errorType]++;
}

void ErrorRecoverySystem::cleanupOldErrors() {
    while (errorHistory.size() > maxErrorHistory) {
        errorHistory.removeFirst();
    }
}

void ErrorRecoverySystem::logError(const ErrorRecord& error) {
    if (!enableDetailedLogging) return;
    
    QString logFile = QString("error_%1.log").arg(QDateTime::currentDateTime().toString("yyyyMMdd"));
    QFile file(logFile);
    
    if (file.open(QIODevice::WriteOnly | QIODevice::Append)) {
        QTextStream stream(&file);
        stream << "[" << error.timestamp.toString("yyyy-MM-dd hh:mm:ss") << "] "
               << error.errorType << " - " << error.component << ": "
               << error.message << "\n";
        
        if (!error.context.isEmpty()) {
            stream << "Context: " << QJsonDocument(error.context).toJson(QJsonDocument::Compact) << "\n";
        }
        
        stream << "---\n";
    }
}
