void PerformanceMonitor::setThreshold(const QString& component, const QString& operation, 
                                     qint64 warningMs, qint64 criticalMs) {
    PerformanceThreshold threshold;
    threshold.component = component;
    threshold.operation = operation;
    threshold.warningThresholdMs = warningMs;
    threshold.criticalThresholdMs = criticalMs;
    
    QString key = QString("%1::%2").arg(component, operation);
    thresholds[key] = threshold;
}

void PerformanceMonitor::recordMetric(const QString& component, const QString& operation, 
                                     qint64 durationMs, const QJsonObject& metadata) {
    PerformanceMetric metric;
    metric.metricId = QString("perf_%1_%2_%3")
        .arg(component, operation)
        .arg(QDateTime::currentDateTime().toMSecsSinceEpoch());
    metric.component = component;
    metric.operation = operation;
    metric.durationMs = durationMs;
    metric.timestamp = QDateTime::currentDateTime().toMSecsSinceEpoch();
    metric.metadata = metadata;
    
    // Check against thresholds
    QString key = QString("%1::%2").arg(component, operation);
    auto thresholdIt = thresholds.find(key);
    if (thresholdIt != thresholds.end()) {
        const PerformanceThreshold& threshold = thresholdIt.value();
        metric.isWithinThreshold = durationMs <= threshold.warningThresholdMs;
        
        if (durationMs > threshold.criticalThresholdMs) {
            emit performanceThresholdExceeded(component, operation, durationMs, "critical");
            emit slowOperationDetected(component, operation, durationMs);
        } else if (durationMs > threshold.warningThresholdMs) {
            emit performanceThresholdExceeded(component, operation, durationMs, "warning");
        }
    } else {
        metric.isWithinThreshold = true; // No threshold defined, assume acceptable
    }
    
    // Store metric
    metricsByComponent[component].append(metric);
    recentMetrics.append(metric);
    
    // Update real-time metrics
    updateRealTimeMetrics(component, operation, durationMs);
    
    // Cleanup if necessary
    if (metricsByComponent[component].size() > maxMetricsPerComponent) {
        metricsByComponent[component].removeFirst();
    }
    
    if (recentMetrics.size() > 100) {
        recentMetrics.removeFirst();
    }
    
    // Log slow operations
    if (durationMs > 1000) { // Operations over 1 second
        std::cout << "[Performance] Slow operation detected: " << component.toStdString() 
                  << "::" << operation.toStdString() << " took " << durationMs << "ms" << std::endl;
    }
}

bool PerformanceMonitor::isPerformanceAcceptable(const QString& component, const QString& operation, 
                                               qint64 durationMs) const {
    QString key = QString("%1::%2").arg(component, operation);
    auto it = thresholds.find(key);
    
    if (it != thresholds.end()) {
        return durationMs <= it.value().warningThresholdMs;
    }
    
    return true; // No threshold defined, assume acceptable
}

void PerformanceMonitor::updateRealTimeMetrics(const QString& component, const QString& operation, qint64 durationMs) {
    QString key = QString("%1::%2").arg(component, operation);
    
    currentResponseTimes[key] = durationMs;
    operationCounts[key]++;
    
    // Update average (simple moving average)
    if (averageResponseTimes.contains(key)) {
        qint64 currentAvg = averageResponseTimes[key];
        qint64 count = operationCounts[key];
        averageResponseTimes[key] = ((currentAvg * (count - 1)) + durationMs) / count;
    } else {
        averageResponseTimes[key] = durationMs;
    }
    
    // Update peak
    if (!peakResponseTimes.contains(key) || durationMs > peakResponseTimes[key]) {
        peakResponseTimes[key] = durationMs;
    }
    
    // Check for performance degradation
    if (averageResponseTimes.contains(key) && operationCounts[key] > 10) {
        qint64 avg = averageResponseTimes[key];
        if (durationMs > avg * 2) { // Performance degraded by more than 2x
            double degradationFactor = static_cast<double>(durationMs) / avg;
            emit performanceDegraded(component, degradationFactor);
        }
    }
}

qint64 PerformanceMonitor::getCurrentResponseTime(const QString& component, const QString& operation) const {
    QString key = QString("%1::%2").arg(component, operation);
    return currentResponseTimes.value(key, -1);
}

