}

QJsonObject PerformanceMonitor::getPerformanceReport(const QString& component) const {
    QJsonObject report;
    
    if (component.isEmpty()) {
        // System-wide report
        QJsonObject summary;
        summary["total_operations"] = recentMetrics.size();
        summary["average_response_time"] = 0;
        summary["slow_operations_count"] = 0;
        
        qint64 totalTime = 0;
        int slowCount = 0;
        
        for (const auto& metric : recentMetrics) {
            totalTime += metric.durationMs;
            if (metric.durationMs > 1000) slowCount++;
        }
        
        if (!recentMetrics.isEmpty()) {
            summary["average_response_time"] = totalTime / recentMetrics.size();
        }
        summary["slow_operations_count"] = slowCount;
        
        report["summary"] = summary;
        
        // Component breakdown
        QJsonObject components;
        for (auto it = metricsByComponent.begin(); it != metricsByComponent.end(); ++it) {
            QJsonObject compReport;
            compReport["operation_count"] = it.value().size();
            compReport["average_response_time"] = 0;
            
            if (!it.value().isEmpty()) {
                qint64 total = 0;
                for (const auto& metric : it.value()) {
                    total += metric.durationMs;
                }
                compReport["average_response_time"] = total / it.value().size();
            }
            
            components[it.key()] = compReport;
        }
        report["components"] = components;
        
    } else {
        // Component-specific report
        auto it = metricsByComponent.find(component);
        if (it != metricsByComponent.end()) {
            report["component"] = component;
            report["operation_count"] = it.value().size();
            
            QJsonObject operations;
            QHash<QString, QVector<qint64>> operationTimes;
            
            for (const auto& metric : it.value()) {
                operationTimes[metric.operation].append(metric.durationMs);
            }
            
            for (auto opIt = operationTimes.begin(); opIt != operationTimes.end(); ++opIt) {
                QJsonObject opReport;
                opReport["count"] = opIt.value().size();
                
                qint64 total = 0;
                qint64 max = 0;
                for (qint64 time : opIt.value()) {
                    total += time;
                    if (time > max) max = time;
                }
                
                opReport["average_time"] = total / opIt.value().size();
                opReport["max_time"] = max;
                operations[opIt.key()] = opReport;
            }
            
            report["operations"] = operations;
        }
    }
    
    return report;
}

QVector<PerformanceMetric> PerformanceMonitor::getSlowOperations(const QString& component, int count) const {
    QVector<PerformanceMetric> slowOps;
    
    if (component.isEmpty()) {
        slowOps = recentMetrics;
    } else {
        auto it = metricsByComponent.find(component);
        if (it != metricsByComponent.end()) {
            slowOps = it.value();
        }
    }
    
    // Sort by duration (slowest first)
    std::sort(slowOps.begin(), slowOps.end(), 
              [](const PerformanceMetric& a, const PerformanceMetric& b) {
                  return a.durationMs > b.durationMs;
              });
    
    if (slowOps.size() > count) {
        slowOps.resize(count);
    }
    
    return slowOps;
}

QJsonObject PerformanceMonitor::getOptimizationSuggestions() const {
    QJsonObject suggestions;
    QJsonArray slowOperations;
    
    QVector<PerformanceMetric> slowOps = getSlowOperations("", 5);
    for (const auto& metric : slowOps) {
        QJsonObject op;
        op["component"] = metric.component;
        op["operation"] = metric.operation;
        op["duration_ms"] = metric.durationMs;
        
        QString key = QString("%1::%2").arg(metric.component, metric.operation);
        auto thresholdIt = thresholds.find(key);
        if (thresholdIt != thresholds.end()) {
            qint64 threshold = thresholdIt.value().warningThresholdMs;
            if (metric.durationMs > threshold * 2) {
                op["priority"] = "high";
                op["suggestion"] = "Consider optimizing this operation - it's significantly slower than threshold";
            } else if (metric.durationMs > threshold) {
                op["priority"] = "medium";
                op["suggestion"] = "This operation exceeds performance thresholds";
            }
        }
        
        slowOperations.append(op);
    }
    
    suggestions["slow_operations"] = slowOperations;
    
    // Component-specific suggestions
    QJsonObject componentSuggestions;
    for (auto it = metricsByComponent.begin(); it != metricsByComponent.end(); ++it) {
        const QString& component = it.key();
        const QVector<PerformanceMetric>& metrics = it.value();
        
        if (metrics.size() < 10) continue; // Need enough data
        
        qint64 totalTime = 0;
        int thresholdViolations = 0;
        
        for (const auto& metric : metrics) {
            totalTime += metric.durationMs;
            
            QString key = QString("%1::%2").arg(metric.component, metric.operation);
            auto thresholdIt = thresholds.find(key);
            if (thresholdIt != thresholds.end()) {
                if (metric.durationMs > thresholdIt.value().warningThresholdMs) {
                    thresholdViolations++;
                }
            }
        }
        
        double violationRate = static_cast<double>(thresholdViolations) / metrics.size();
        
        if (violationRate > 0.3) { // More than 30% violations
            QJsonObject compSuggestion;
            compSuggestion["violation_rate"] = violationRate;
            compSuggestion["suggestion"] = "Consider reviewing component architecture for performance improvements";
            componentSuggestions[component] = compSuggestion;
        }
    }
    
    suggestions["component_issues"] = componentSuggestions;
    
    return suggestions;
}

double PerformanceMonitor::getSLACompliance(const QString& component) const {
    QVector<PerformanceMetric> metrics;
    
    if (component.isEmpty()) {
        metrics = recentMetrics;
    } else {
        auto it = metricsByComponent.find(component);
        if (it != metricsByComponent.end()) {
            metrics = it.value();
        }
    }
    
    return calculateSLACompliance(metrics);
}

double PerformanceMonitor::calculateSLACompliance(const QVector<PerformanceMetric>& metrics) const {
    if (metrics.isEmpty()) return 1.0;
    
    int compliantOperations = 0;
    
    for (const auto& metric : metrics) {
        if (metric.isWithinThreshold) {
            compliantOperations++;
        }
    }
    
    return static_cast<double>(compliantOperations) / metrics.size();
}

void PerformanceMonitor::cleanupOldMetrics() {
    // Remove metrics older than 24 hours
    qint64 cutoffTime = QDateTime::currentDateTime().addSecs(-86400).toMSecsSinceEpoch();
    
    for (auto it = metricsByComponent.begin(); it != metricsByComponent.end(); ++it) {
        QVector<PerformanceMetric>& metrics = it.value();
        metrics.erase(std::remove_if(metrics.begin(), metrics.end(),
                                    [cutoffTime](const PerformanceMetric& metric) {
                                        return metric.timestamp < cutoffTime;
                                    }), metrics.end());
    }
    
    recentMetrics.erase(std::remove_if(recentMetrics.begin(), recentMetrics.end(),
                                      [cutoffTime](const PerformanceMetric& metric) {
                                          return metric.timestamp < cutoffTime;
                                      }), recentMetrics.end());
}

void PerformanceMonitor::startRealTimeMonitoring() {
    metricsTimer->start(5000); // Update every 5 seconds
    cleanupTimer->start();
}

void PerformanceMonitor::stopRealTimeMonitoring() {
    metricsTimer->stop();
    cleanupTimer->stop();
}
