        if (userId.isEmpty() || credentials.isEmpty()) {
            logSecurityEvent(userId, "authentication_failed", "authentication_service",
                           QJsonObject{{"reason", "invalid_input"}});
            return false;
        }
        
        // Check for brute force attempts
        static QHash<QString, int> failedAttempts;
        if (failedAttempts[userId] >= 5) {
