                           QJsonObject{{"reason", "too_many_failed_attempts"}});
            emit securityAlert("account_lockout", QString("Account locked due to too many failed attempts: %1").arg(userId));
            return false;
        }
        
        // In a real implementation, this would validate against LDAP/AD database
        // For demo purposes, accept specific test credentials
        bool authenticated = false;
        if (userId == "admin" && credentials == "SecureAdmin2024!") {
            authenticated = true;
        } else if (userId == "developer" && credentials == "DevPass2024!") {
            authenticated = true;
        }
        
        if (authenticated) {
            failedAttempts.remove(userId);
