void EnterpriseSecurityManager::logSecurityEvent(const QString& userId, const QString& action, 
                                               const QString& resource, const QJsonObject& details) {
    if (!enableAuditLogging) return;
    
    SecurityAudit audit;
    audit.auditId = QString("audit_%1_%2").arg(userId).arg(QDateTime::currentDateTime().toMSecsSinceEpoch());
    audit.userId = userId;
    audit.action = action;
    audit.resource = resource;
    audit.details = details;
    audit.timestamp = QDateTime::currentDateTime();
    audit.isAuthorized = true; // Will be validated by authorizeAction
    
    // Check if this violates any security policies
    QVector<SecurityPolicy> applicablePolicies = getApplicablePolicies("audit_logging");
    for (const SecurityPolicy& policy : applicablePolicies) {
        if (!policy.isEnabled) continue;
        
        // Check for policy violations
        if (action.contains("unauthorized") || action.contains("violation")) {
            audit.isAuthorized = false;
            audit.policyViolated = policy.policyId;
            emit policyViolationDetected(policy.policyId, userId);
        }
    }
    
    logSecurityAudit(audit);
    
    // Real-time threat detection
    if (detectAnomalousBehavior(userId, action, details)) {
        emit securityAlert("anomalous_behavior", QString("Anomalous behavior detected from user: %1").arg(userId));
    }
}

bool EnterpriseSecurityManager::detectAnomalousBehavior(const QString& userId, const QString& action, 
                                                       const QJsonObject& context) {
    // Simple anomaly detection - in production, use ML models
    static QHash<QString, int> actionCounts;
    actionCounts[QString("%1::%2").arg(userId, action)]++;
    
    int count = actionCounts[QString("%1::%2").arg(userId, action)];
    
    // Flag if same action performed more than 100 times in short period
    if (count > 100) {
        emit anomalousBehaviorDetected(userId, action);
        return true;
    }
    
    // Flag unusual access patterns
    if (action.contains("access") && context.contains("resource")) {
        QString resource = context["resource"].toString();
        if (resource.contains("admin") && !userId.contains("admin")) {
            return true;
        }
    }
    
    return false;
}

QByteArray EnterpriseSecurityManager::generateSecureToken(int length) {
    QByteArray token;
    token.reserve(length);
    
    const QString chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789!@#$%^&*()_+-=[]{}|;:,.<>?";
    
    for (int i = 0; i < length; ++i) {
        int index = QRandomGenerator::global()->bounded(chars.length());
        token.append(chars[index].toLatin1());
    }
    
    return token;
}

QJsonObject EnterpriseSecurityManager::getSecurityDashboard() const {
    QJsonObject dashboard;
    
    dashboard["encryption_enabled"] = enableEncryption;
    dashboard["access_control_enabled"] = enableAccessControl;
    dashboard["audit_logging_enabled"] = enableAuditLogging;
    dashboard["compliance_mode_enabled"] = enableComplianceMode;
    dashboard["compliance_level"] = complianceLevel;
    
    // Key statistics
    int activeKeys = 0;
    int expiredKeys = 0;
    for (const auto& [keyId, key] : encryptionKeys) {
        if (key.isActive) activeKeys++;
        if (QDateTime::currentDateTime() > key.expires) expiredKeys++;
    }
    
    dashboard["active_encryption_keys"] = activeKeys;
    dashboard["expired_keys"] = expiredKeys;
    
    // Policy statistics
    dashboard["total_policies"] = securityPolicies.size();
    
    int enabledPolicies = 0;
    for (const auto& [policyId, policy] : securityPolicies) {
        if (policy.isEnabled) enabledPolicies++;
    }
    dashboard["enabled_policies"] = enabledPolicies;
    
    // Recent security events
    QJsonArray recentEvents;
    int eventCount = 0;
    for (auto it = securityAuditLog.rbegin(); it != securityAuditLog.rend() && eventCount < 10; ++it) {
        QJsonObject event;
        event["timestamp"] = it->timestamp.toString(Qt::ISODate);
        event["user_id"] = it->userId;
        event["action"] = it->action;
        event["resource"] = it->resource;
        event["is_authorized"] = it->isAuthorized;
        recentEvents.append(event);
        eventCount++;
    }
    dashboard["recent_security_events"] = recentEvents;
    
    return dashboard;
}

void EnterpriseSecurityManager::enableComplianceMode(const QString& complianceStandard) {
    enableComplianceMode = true;
    complianceLevel = complianceStandard;
    
    // Apply compliance-specific security policies
    if (complianceStandard == "HIPAA") {
        // Healthcare data protection requirements
        SecurityPolicy hipaaPolicy;
        hipaaPolicy.policyId = "hipaa_data_protection";
        hipaaPolicy.name = "HIPAA Data Protection";
        hipaaPolicy.type = "compliance";
        hipaaPolicy.isEnabled = true;
        hipaaPolicy.rules = QJsonObject{
            {"phi_encryption_required", true},
            {"access_logging_required", true},
            {"minimum_password_length", 12},
            {"session_timeout_minutes", 15},
            {"audit_retention_years", 7}
        };
        securityPolicies[hipaaPolicy.policyId] = hipaaPolicy;
        
    } else if (complianceStandard == "SOX") {
        // Sarbanes-Oxley financial compliance
        SecurityPolicy soxPolicy;
        soxPolicy.policyId = "sox_compliance";
        soxPolicy.name = "SOX Financial Data Protection";
        soxPolicy.type = "compliance";
        soxPolicy.isEnabled = true;
        soxPolicy.rules = QJsonObject{
            {"financial_data_encryption", true},
            {"change_approval_required", true},
            {"segregation_of_duties", true},
            {"audit_trail_required", true}
        };
        securityPolicies[soxPolicy.policyId] = soxPolicy;
    }
    
    emit securityAlert("compliance_enabled", QString("Compliance mode enabled for %1").arg(complianceStandard));
    
    std::cout << "[EnterpriseSecurity] Compliance mode enabled: " << complianceStandard.toStdString() << std::endl;
}
