YELLOW='\033[1;33m'
BLUE='\033[0;34m'
NC='\033[0m'

# Configuration
BUILD_TYPE=${BUILD_TYPE:-Release}
ENTERPRISE_FEATURES=${ENTERPRISE_FEATURES:-ON}
SECURITY_COMPLIANCE=${SECURITY_COMPLIANCE:-SOX}
ENABLE_MONITORING=${ENABLE_MONITORING:-ON}
CONTAINER_BUILD=${CONTAINER_BUILD:-OFF}

log_info() {
    echo -e "${BLUE}[INFO]${NC} $1"
}

log_success() {
    echo -e "${GREEN}[SUCCESS]${NC} $1"
}

log_warning() {
    echo -e "${YELLOW}[WARNING]${NC} $1"
}

log_error() {
    echo -e "${RED}[ERROR]${NC} $1"
}

# System verification
verify_system() {
    log_info "Verifying system requirements..."
    
    # Check memory (minimum 8GB for enterprise build)
    TOTAL_MEM=$(free -g | awk 'NR==2{print $2}')
    if [ "$TOTAL_MEM" -lt 8 ]; then
        log_warning "System has less than 8GB RAM. Enterprise build may be slow."
    fi
    
    # Check disk space (minimum 20GB)
    AVAILABLE_SPACE=$(df -BG . | awk 'NR==2{print $4}' | sed 's/G//')
    if [ "$AVAILABLE_SPACE" -lt 20 ]; then
        log_error "Insufficient disk space. Need at least 20GB available."
        exit 1
    fi
    
    # Verify required tools
    for tool in cmake g++ git; do
        if ! command -v $tool &> /dev/null; then
            log_error "Required tool not found: $tool"
            exit 1
        fi
    done
    
    log_success "System verification completed"
}

# Security scan
security_scan() {
    log_info "Running security scan on source code..."
    
    # Check for common security issues
    SECURITY_ISSUES=0
    
    # Check for hardcoded passwords
    if grep -r "password.*=" src/ | grep -v "password.*=.*getenv\|password.*=.*config" | grep -v "security_test"; then
        log_warning "Potential hardcoded passwords detected"
        SECURITY_ISSUES=$((SECURITY_ISSUES + 1))
    fi
    
    # Check for buffer overflow risks
    if grep -r "strcpy\|strcat\|gets" src/ | grep -v "security_test"; then
        log_warning "Unsafe string functions detected"
        SECURITY_ISSUES=$((SECURITY_ISSUES + 1))
    fi
    
    # Check for SQL injection risks
    if grep -r "SELECT.*+.*\|INSERT.*+.*\|UPDATE.*+.*" src/ | grep -v "security_test"; then
        log_warning "Potential SQL injection vulnerabilities detected"
        SECURITY_ISSUES=$((SECURITY_ISSUES + 1))
    fi
    
    if [ $SECURITY_ISSUES -eq 0 ]; then
        log_success "No security issues detected"
    else
        log_warning "Found $SECURITY_ISSUES potential security issues"
    fi
}

# Enterprise build
enterprise_build() {
    log_info "Starting enterprise build..."
    
    # Create build directory
    mkdir -p build_enterprise
    cd build_enterprise
    
    # Configure with enterprise flags
    cmake .. \
        -DCMAKE_BUILD_TYPE=$BUILD_TYPE \
        -DENTERPRISE_FEATURES=$ENTERPRISE_FEATURES \
        -DSECURITY_COMPLIANCE=$SECURITY_COMPLIANCE \
        -DENABLE_MONITORING=$ENABLE_MONITORING \
        -DCONTAINER_BUILD=$CONTAINER_BUILD \
        -DENABLE_STATIC_ANALYSIS=ON \
        -DENABLE_SECURITY_HARDENING=ON \
        -DENABLE_PERFORMANCE_PROFILING=ON \
        -G "Unix Makefiles"
    
    if [ $? -ne 0 ]; then
        log_error "CMake configuration failed"
        exit 1
    fi
    
    # Build with parallel jobs
    log_info "Building with $(nproc) parallel jobs..."
    cmake --build . --parallel $(nproc) --target RawrXD-AgenticIDE
    
    if [ $? -ne 0 ]; then
        log_error "Build failed"
        exit 1
    fi
    
    log_success "Enterprise build completed successfully"
}

# Static analysis
static_analysis() {
    log_info "Running static analysis..."
    
    # Run cppcheck if available
    if command -v cppcheck &> /dev/null; then
        log_info "Running cppcheck..."
        cppcheck --enable=all --inconclusive --std=c++20 \
                 --suppress=missingIncludeSystem \
                 --suppress=unusedFunction \
                 --suppress=unmatchedSuppression \
                 src/ || true
    fi
    
    # Run clang-tidy if available
    if command -v clang-tidy &> /dev/null; then
        log_info "Running clang-tidy..."
        find src/ -name "*.cpp" -o -name "*.h" | xargs clang-tidy \
            -checks='-*,bugprone-*,cert-*,clang-analyzer-*,cppcoreguidelines-*,hicpp-*,llvm-*,misc-*,modernize-*,performance-*,readability-*,security-*' \
            -- -std=c++20 || true
    fi
    
    log_success "Static analysis completed"
}

# Performance profiling
performance_profile() {
    log_info "Running performance profiling..."
    
    # Build with profiling flags
    cmake .. -DCMAKE_BUILD_TYPE=RelWithDebInfo -DENABLE_PROFILING=ON
    
    # Run performance tests
    if [ -f "bin/RawrXD-AgenticIDE" ]; then
        log_info "Running performance benchmarks..."
        # Add performance test execution here
    fi
    
    log_success "Performance profiling completed"
}

# Package creation
create_packages() {
    log_info "Creating deployment packages..."
    
    # Create release package
    mkdir -p package/release
    cp bin/RawrXD-AgenticIDE package/release/
    cp -r resources package/release/
    cp LICENSE package/release/
    cp README.md package/release/
    
    # Create configuration package
    mkdir -p package/config
    cp config/enterprise.json package/config/
    cp config/security-policies.json package/config/
    
    # Create Docker image if requested
    if [ "$CONTAINER_BUILD" = "ON" ]; then
        log_info "Building Docker image..."
        docker build -t rawrxd/agentic-ide:enterprise-v1.0.0 .
        docker tag rawrxd/agentic-ide:enterprise-v1.0.0 rawrxd/agentic-ide:latest
        
        # Save Docker image
        docker save rawrxd/agentic-ide:enterprise-v1.0.0 | gzip > package/rawrxd-agentic-ide-enterprise.tar.gz
    fi
    
    # Create installer package
    cd package
    tar -czf rawrxd-agentic-ide-enterprise-v1.0.0.tar.gz release/ config/
    cd ..
    
    log_success "Packages created successfully"
}

# Generate documentation
generate_docs() {
    log_info "Generating documentation..."
    
    # Create documentation directory
    mkdir -p docs
    
    # Generate API documentation if Doxygen is available
    if command -v doxygen &> /dev/null; then
        cat > Doxyfile << EOF
PROJECT_NAME = "RawrXD Agentic IDE"
OUTPUT_DIRECTORY = docs
INPUT = src include
RECURSIVE = YES
EXTRACT_ALL = YES
GENERATE_HTML = YES
GENERATE_LATEX = NO
EOF
        doxygen Doxyfile
    fi
    
    # Generate security documentation
    cat > docs/SECURITY.md << EOF
# Security Documentation

## Enterprise Security Features

### Encryption
- AES-256 encryption for data at rest
- TLS 1.3 for data in transit
- Key rotation every 30 days
- Hardware security module support

### Access Control
- Role-based access control (RBAC)
- Multi-factor authentication (MFA)
- Single sign-on (SSO) integration
- Session management with timeout

### Compliance
- SOX compliance enabled
- Audit logging for all operations
- Data retention policies
- Privacy controls

### Monitoring
- Real-time security alerts
- Anomaly detection
- Threat intelligence integration
- Incident response automation
EOF
    
    log_success "Documentation generated"
}

# Main execution
main() {
    log_info "Starting RawrXD Agentic IDE Enterprise Build"
    log_info "Build Configuration:"
    log_info "  Build Type: $BUILD_TYPE"
    log_info "  Enterprise Features: $ENTERPRISE_FEATURES"
    log_info "  Security Compliance: $SECURITY_COMPLIANCE"
    log_info "  Container Build: $CONTAINER_BUILD"
    
    # Run all build phases
    verify_system
    security_scan
    enterprise_build
    static_analysis
    performance_profile
    create_packages
    generate_docs
    
    # Final summary
    log_success "Enterprise build completed successfully!"
    log_info "Artifacts created:"
    log_info "  - Binary: build_enterprise/bin/RawrXD-AgenticIDE"
    log_info "  - Package: package/rawrxd-agentic-ide-enterprise-v1.0.0.tar.gz"
    if [ "$CONTAINER_BUILD" = "ON" ]; then
        log_info "  - Docker Image: rawrxd/agentic-ide:enterprise-v1.0.0"
    fi
    log_info "  - Documentation: docs/"
    
    # Performance summary
    if [ -f "build_enterprise/performance_report.json" ]; then
        log_info "Performance summary available in build_enterprise/performance_report.json"
    fi
    
    # Security summary
    if [ -f "build_enterprise/security_report.json" ]; then
        log_info "Security summary available in build_enterprise/security_report.json"
    fi
}

# Run main function
